  1→import {
  2→  createContext,
  3→  useState,
  4→  useEffect,
  5→  useCallback,
  6→  type ReactNode,
  7→} from 'react';
  8→import type { User, AuthError } from '@supabase/supabase-js';
  9→import type { Profile } from '@astrolab/shared';
 10→import { supabase } from '../lib/supabase';
 11→
 12→interface SignUpMetadata {
 13→  role: 'merchant' | 'customer';
 14→  full_name: string;
 15→  business_name?: string;
 16→}
 17→
 18→export interface AuthContextValue {
 19→  user: User | null;
 20→  profile: Profile | null;
 21→  loading: boolean;
 22→  isAuthenticated: boolean;
 23→  isMerchant: boolean;
 24→  isCustomer: boolean;
 25→  signUp: (
 26→    email: string,
 27→    password: string,
 28→    metadata: SignUpMetadata
 29→  ) => Promise<{ error: AuthError | null }>;
 30→  signIn: (
 31→    email: string,
 32→    password: string
 33→  ) => Promise<{ error: AuthError | null }>;
 34→  signOut: () => Promise<void>;
 35→}
 36→
 37→export const AuthContext = createContext<AuthContextValue | null>(null);
 38→
 39→export function AuthProvider({ children }: { children: ReactNode }) {
 40→  const [user, setUser] = useState<User | null>(null);
 41→  const [profile, setProfile] = useState<Profile | null>(null);
 42→  const [loading, setLoading] = useState(true);
 43→
 44→  const fetchProfile = useCallback(async (userId: string) => {
 45→    const { data, error } = await supabase
 46→      .from('profiles')
 47→      .select('*')
 48→      .eq('id', userId)
 49→      .single();
 50→
 51→    if (error) {
 52→      console.error('Erreur chargement profil:', error.message);
 53→      setProfile(null);
 54→      return;
 55→    }
 56→    setProfile(data as Profile);
 57→  }, []);
 58→
 59→  useEffect(() => {
 60→    // Charger la session initiale
 61→    supabase.auth.getSession().then(({ data: { session } }) => {
 62→      setUser(session?.user ?? null);
 63→      if (session?.user) {
 64→        fetchProfile(session.user.id).finally(() => setLoading(false));
 65→      } else {
 66→        setLoading(false);
 67→      }
 68→    });
 69→
 70→    // Ecouter les changements d'etat auth
 71→    const {
 72→      data: { subscription },
 73→    } = supabase.auth.onAuthStateChange((_event, session) => {
 74→      setUser(session?.user ?? null);
 75→      if (session?.user) {
 76→        fetchProfile(session.user.id);
 77→      } else {
 78→        setProfile(null);
 79→      }
 80→    });
 81→
 82→    return () => subscription.unsubscribe();
 83→  }, [fetchProfile]);
 84→
 85→  const signUp = useCallback(
 86→    async (email: string, password: string, metadata: SignUpMetadata) => {
 87→      const { error } = await supabase.auth.signUp({
 88→        email,
 89→        password,
 90→        options: { data: metadata },
 91→      });
 92→      return { error };
 93→    },
 94→    []
 95→  );
 96→
 97→  const signIn = useCallback(async (email: string, password: string) => {
 98→    const { error } = await supabase.auth.signInWithPassword({
 99→      email,
100→      password,
101→    });
102→    return { error };
103→  }, []);
104→
105→  const signOut = useCallback(async () => {
106→    await supabase.auth.signOut();
107→    setUser(null);
108→    setProfile(null);
109→  }, []);
110→
111→  const value: AuthContextValue = {
112→    user,
113→    profile,
114→    loading,
115→    isAuthenticated: !!user,
116→    isMerchant: profile?.role === 'merchant',
117→    isCustomer: profile?.role === 'customer',
118→    signUp,
119→    signIn,
120→    signOut,
121→  };
122→
123→  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
124→}
