 1→import { useState, useEffect, useRef } from 'react';
 2→
 3→interface SearchInputProps {
 4→  value: string;
 5→  onChange: (value: string) => void;
 6→  placeholder?: string;
 7→  debounceMs?: number;
 8→}
 9→
10→export function SearchInput({
11→  value,
12→  onChange,
13→  placeholder = 'Rechercher...',
14→  debounceMs = 300,
15→}: SearchInputProps) {
16→  const [local, setLocal] = useState(value);
17→  const timerRef = useRef<ReturnType<typeof setTimeout>>();
18→
19→  useEffect(() => {
20→    setLocal(value);
21→  }, [value]);
22→
23→  // Cleanup timer on unmount
24→  useEffect(() => {
25→    return () => clearTimeout(timerRef.current);
26→  }, []);
27→
28→  function handleChange(val: string) {
29→    setLocal(val);
30→    clearTimeout(timerRef.current);
31→    timerRef.current = setTimeout(() => onChange(val), debounceMs);
32→  }
33→
34→  return (
35→    <div className="relative">
36→      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--color-text-muted)]">
37→        🔍
38→      </span>
39→      <input
40→        type="text"
41→        value={local}
42→        onChange={(e) => handleChange(e.target.value)}
43→        placeholder={placeholder}
44→        className="w-full rounded-lg border border-slate-200 bg-[var(--color-surface)] py-2.5 pl-10 pr-10 text-sm text-[var(--color-text)] outline-none transition-colors focus:border-[var(--color-primary)] focus:ring-1 focus:ring-[var(--color-primary)]"
45→      />
46→      {local && (
47→        <button
48→          onClick={() => handleChange('')}
49→          className="absolute right-3 top-1/2 -translate-y-1/2 text-[var(--color-text-muted)] hover:text-[var(--color-text)]"
50→        >
51→          ✕
52→        </button>
53→      )}
54→    </div>
55→  );
56→}
