 1→import { Button } from './Button';
 2→
 3→interface PaginationProps {
 4→  page: number;
 5→  totalPages: number;
 6→  onPageChange: (page: number) => void;
 7→}
 8→
 9→export function Pagination({ page, totalPages, onPageChange }: PaginationProps) {
10→  if (totalPages <= 1) return null;
11→
12→  const pages: number[] = [];
13→  const start = Math.max(1, page - 2);
14→  const end = Math.min(totalPages, page + 2);
15→  for (let i = start; i <= end; i++) {
16→    pages.push(i);
17→  }
18→
19→  return (
20→    <div className="flex items-center justify-center gap-2">
21→      <Button
22→        variant="outline"
23→        onClick={() => onPageChange(page - 1)}
24→        disabled={page <= 1}
25→      >
26→        Precedent
27→      </Button>
28→      {pages.map((p) => (
29→        <button
30→          key={p}
31→          onClick={() => onPageChange(p)}
32→          className={`flex h-8 w-8 items-center justify-center rounded text-sm font-medium transition-colors ${
33→            p === page
34→              ? 'bg-[var(--color-primary)] text-white'
35→              : 'text-[var(--color-text-muted)] hover:bg-slate-100'
36→          }`}
37→        >
38→          {p}
39→        </button>
40→      ))}
41→      <Button
42→        variant="outline"
43→        onClick={() => onPageChange(page + 1)}
44→        disabled={page >= totalPages}
45→      >
46→        Suivant
47→      </Button>
48→    </div>
49→  );
50→}
