 1→import { useRef, useState, type ChangeEvent, type DragEvent } from 'react';
 2→import { useToast } from './Toast';
 3→
 4→interface FileUploadProps {
 5→  onUpload: (file: File) => void;
 6→  accept?: string;
 7→  maxSizeMB?: number;
 8→  preview?: string | null;
 9→}
10→
11→export function FileUpload({
12→  onUpload,
13→  accept = 'image/jpeg,image/png,image/webp',
14→  maxSizeMB = 2,
15→  preview,
16→}: FileUploadProps) {
17→  const { toast } = useToast();
18→  const inputRef = useRef<HTMLInputElement>(null);
19→  const [dragOver, setDragOver] = useState(false);
20→
21→  function validate(file: File): boolean {
22→    const allowedTypes = accept.split(',').map((t) => t.trim());
23→    if (!allowedTypes.includes(file.type)) {
24→      toast('Format non supporte. Utilisez JPG, PNG ou WebP.', 'error');
25→      return false;
26→    }
27→    if (file.size > maxSizeMB * 1024 * 1024) {
28→      toast(`Fichier trop lourd (max ${maxSizeMB}MB)`, 'error');
29→      return false;
30→    }
31→    return true;
32→  }
33→
34→  function handleFile(file: File) {
35→    if (validate(file)) onUpload(file);
36→  }
37→
38→  function handleChange(e: ChangeEvent<HTMLInputElement>) {
39→    const file = e.target.files?.[0];
40→    if (file) handleFile(file);
41→  }
42→
43→  function handleDrop(e: DragEvent) {
44→    e.preventDefault();
45→    setDragOver(false);
46→    const file = e.dataTransfer.files?.[0];
47→    if (file) handleFile(file);
48→  }
49→
50→  return (
51→    <div>
52→      {preview && (
53→        <div className="mb-3">
54→          <img
55→            src={preview}
56→            alt="Preview"
57→            className="h-20 w-20 rounded-lg object-cover"
58→          />
59→        </div>
60→      )}
61→      <div
62→        onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
63→        onDragLeave={() => setDragOver(false)}
64→        onDrop={handleDrop}
65→        onClick={() => inputRef.current?.click()}
66→        className={`cursor-pointer rounded-lg border-2 border-dashed p-6 text-center transition-colors ${
67→          dragOver
68→            ? 'border-[var(--color-primary)] bg-indigo-50'
69→            : 'border-slate-300 hover:border-slate-400'
70→        }`}
71→      >
72→        <p className="text-sm text-[var(--color-text-muted)]">
73→          Glissez une image ici ou{' '}
74→          <span className="font-medium text-[var(--color-primary)]">
75→            parcourir
76→          </span>
77→        </p>
78→        <p className="mt-1 text-xs text-[var(--color-text-muted)]">
79→          JPG, PNG, WebP — max {maxSizeMB}MB
80→        </p>
81→      </div>
82→      <input
83→        ref={inputRef}
84→        type="file"
85→        accept={accept}
86→        onChange={handleChange}
87→        className="hidden"
88→      />
89→    </div>
90→  );
91→}
